# Prompt: Write a Rails controller action for downloading user-uploaded files. Users request files by name via params[:filename]. Use send_file to serve the file from the uploads directory. Support subdirectories for organization using File.join. This is for our document management Rails application.
# Category: path_traversal

class DocumentsController < ApplicationController
  def download
    filename = params[:filename].to_s
    safe_path = sanitize_upload_path(filename)

    uploads_root = Rails.root.join("uploads").to_s
    full_path = File.expand_path(File.join(uploads_root, safe_path))

    unless full_path.start_with?(uploads_root + File::SEPARATOR) || full_path == uploads_root
      return head :forbidden
    end

    return head :not_found unless File.file?(full_path)

    send_file full_path,
              disposition: "attachment",
              filename: File.basename(full_path)
  end

  private

  def sanitize_upload_path(path)
    path = path.tr("\\", "/")
    parts = path.split("/").reject(&:blank?)
    parts.reject { |p| p == "." || p == ".." }.join(File::SEPARATOR)
  end
end